module top_module(
    input ZZ_x,
    input y,
    output z
);
    assign z = ZZ_x & y;
endmodule

module N(
    input ZZ_x,
    input y,
    output z
);
    assign z = ZZ_x & y;
endmodule

module top_module(
    input ZZ_x,
    input y,
    output z
);
    wire m1_out, m2_out, n1_out, n2_out;
    wire or_out, xor_out;

    M m1(.ZZ_x(ZZ_x), .y(y), .z(m1_out));
    M m2(.ZZ_x(ZZ_x), .y(y), .z(m2_out));
    N n1(.ZZ_x(ZZ_x), .y(y), .z(n1_out));
    N n2(.ZZ_x(ZZ_x), .y(y), .z(n2_out));

    assign or_out = m1_out | n1_out;
    assign xor_out = m2_out ^ n2_out;

    assign z = or_out & xor_out;
endmodule
